import{_ as a,o as e,c as t,Q as o}from"./chunks/framework.3daba8ea.js";const m=JSON.parse('{"title":"信号量","description":null,"frontmatter":{"lang":"zh-CN","title":"信号量","description":null},"headers":[],"relativePath":"doc/编程语言/Go/基础/gmp/信号量.md","filePath":"packages/doc/src/编程语言/Go/基础/gmp/信号量.md","lastUpdated":1704297641000}'),p={name:"doc/编程语言/Go/基础/gmp/信号量.md"},r=o('<h1 id="信号量" tabindex="-1">信号量 <a class="header-anchor" href="#信号量" aria-label="Permalink to &quot;信号量&quot;">​</a></h1><h2 id="_1-自旋锁" tabindex="-1">1.自旋锁 <a class="header-anchor" href="#_1-自旋锁" aria-label="Permalink to &quot;1.自旋锁&quot;">​</a></h2><p>获取锁失败，屡败屡战，知道CPU时间片用完，这种方式叫自旋锁</p><h2 id="_2-调度器对象" tabindex="-1">2.调度器对象 <a class="header-anchor" href="#_2-调度器对象" aria-label="Permalink to &quot;2.调度器对象&quot;">​</a></h2><p>获取不到锁，等待操作系统安排，进入等待队列</p><p>等待队列，可以挂起，唤醒线程，自旋锁做不到</p><p>同步原语，内核对象</p><p>windows的 Event,linux 的Futex</p><p>需要系统调用来实现，会涉及到线程切换，开销大</p><h2 id="_3-总结-各有各的应用场景" tabindex="-1">3.总结，各有各的应用场景 <a class="header-anchor" href="#_3-总结-各有各的应用场景" aria-label="Permalink to &quot;3.总结，各有各的应用场景&quot;">​</a></h2><p>针对线程设计：</p><p>自旋锁 ：多核，锁时间短，自旋几次就能拿到锁，比切换线程代驾小</p><p>调度器对象：单核，空耗CPU得不偿失,持有锁的时间占比较大</p><p>实际应用往往是先自旋几次,然后再搭配调度器对象进行加锁,Mutex实现方式</p><h2 id="_4-协程怎么做-通过信号量" tabindex="-1">4.协程怎么做？通过信号量 <a class="header-anchor" href="#_4-协程怎么做-通过信号量" aria-label="Permalink to &quot;4.协程怎么做？通过信号量&quot;">​</a></h2><p>协程等待锁不需要切换线程</p><p>如何休眠，等待唤醒？</p><p>samphore信号量，semTable,平衡树的根，sudog,所有的g等待队列都存在这个平衡树上。</p><p>Mutex结果体有一个sema字段就是表示信号量</p><p>channel自己实现排队机制，因为有读写等待队列</p>',20),n=[r];function s(l,i,_,c,d,h){return e(),t("div",null,n)}const f=a(p,[["render",s]]);export{m as __pageData,f as default};
